// hooks/useFormManager.ts

import {type Dispatch, type SetStateAction, useCallback, useEffect, useMemo} from 'react';
import {type FieldValues, type SubmitHandler, useForm, type UseFormReturn, type DefaultValues} from 'react-hook-form';
import {yupResolver} from '@hookform/resolvers/yup';
import {checkNameDuplication, getCombinedChildIds, getDefaultValues, schemaBuilder} from '../utils';
import type {IFormComponent} from '@lmb-it/kitsconcerto-types';

// --- Using Your Provided Type Definitions ---


// --- CORRECTED RETURN TYPE ---
export interface UseFormManagerReturn<T extends FieldValues> {
    /**
     * The original, unmodified methods returned from react-hook-form's useForm hook.
     * This is what gets passed to the FormProvider.
     */
    formMethods: UseFormReturn<T>;
    /**
     * Our custom loading state for the submit button.
     */
    isSubmitting: boolean;
    /**
     * Our wrapped submit handler that manages the isSubmitting state.
     * This is what the <form> element's onSubmit will call.
     */
    handleSubmit: () => void;

    setIsSubmitting: Dispatch<SetStateAction<boolean>>
}

// A helper utility to check for valid URLs, as used in your original getDefaultValues.
const isValidURL = (urlString: string): boolean => {
    try {
        const url = new URL(urlString);
        return ['http:', 'https:'].includes(url.protocol);
    } catch (_) {
        return false;
    }
};

export const useFormManager = <T extends FieldValues>({
                                                          elements,
                                                          onSubmit,
                                                          onInvalidSubmit, id,
                                                          onChange,
                                                          onChangeSingleValue, // <-- Add this
                                                          outputFormat = 'Json'
                                                      }: IFormComponent<T>, isSubmitting: boolean, setIsSubmitting: Dispatch<SetStateAction<boolean>>): UseFormManagerReturn<T> => {


    // 1. Check for duplicate names on mount and when elements change.
    useEffect(() => {
        try {
            checkNameDuplication(elements);
        } catch (error) {
            console.error("Form Configuration Error:", error);
        }
    }, [elements]);

    // 2. Generate the default values object, memoized for performance.
    const defaultValues = useMemo(() => getDefaultValues(elements), [elements]);

    const schema = useMemo(() => schemaBuilder(elements, id!), [elements]);

    // 2b. Collect Combined children IDs to exclude from output data.
    const combinedChildIds = useMemo(() => getCombinedChildIds(elements), [elements]);

    const stripCombinedChildren = useCallback((data: Record<string, any>) => {
        if (combinedChildIds.size === 0) return data;
        const filtered: Record<string, any> = {};
        for (const [key, value] of Object.entries(data)) {
            if (!combinedChildIds.has(key)) {
                filtered[key] = value;
            }
        }
        return filtered;
    }, [combinedChildIds]);

    // console.log(id, elements, schema)

    // console.log(schema.describe())
    // This is the original, unmodified object from react-hook-form
    const formMethods = useForm<T>({
        resolver: yupResolver(schema),
        defaultValues: defaultValues as DefaultValues<T>,
        shouldUnregister: false,
        mode: "onSubmit",
        reValidateMode: "onChange",
        // ... (defaultValues logic remains the same)
    });


    const onValidSubmit: SubmitHandler<any> = useCallback(
        (rawData) => {
            const data = stripCombinedChildren(rawData);
            if (outputFormat === "FormData") {
                const formData = new FormData();
                for (const [key, value] of Object.entries(data)) {
                    if (Array.isArray(value)) {
                        if (value.length === 1 && value[0] instanceof File) {
                            formData.append(key, value[0]);
                        } else {
                            value.forEach((item) => {
                                if (item instanceof File) {
                                    formData.append(`${key}[]`, item);
                                } else if (
                                    typeof item === "number" ||
                                    typeof item === "string"
                                ) {
                                    formData.append(`${key}[]`, item.toString());
                                } else {
                                    formData.append(`${key}[]`, JSON.stringify(item));
                                }
                            });
                        }
                    } else {
                        if (value instanceof File) {
                            formData.append(key, value);
                        } else if (
                            typeof value === "number" ||
                            typeof value === "string"
                        ) {
                            formData.append(key, value.toString());
                        } else {
                            formData.append(key, JSON.stringify(value));
                        }
                    }
                }

                onSubmit && onSubmit(formData, setIsSubmitting, formMethods);
            } else {
                onSubmit && onSubmit(data, setIsSubmitting, formMethods);
            }
        },
        [outputFormat, onSubmit, setIsSubmitting, formMethods, stripCombinedChildren],
    );


    // Our custom wrapper function
    const handleSubmitWrapper = useCallback(() => {
        // We call the ORIGINAL handleSubmit from formMethods here
        formMethods.handleSubmit(onValidSubmit, (errors) => {
            setIsSubmitting(false);
            onInvalidSubmit?.(errors);
        })();
    }, [formMethods, onValidSubmit, setIsSubmitting, onInvalidSubmit]);

    function getValueByPath(obj: any, path: string) {
        return path.split(".").reduce((acc, key) => {
            if (acc === undefined || acc === null) return undefined;
            return acc[key];
        }, obj);
    }

    // This useEffect hook handles both global and single-value change events.
    useEffect(() => {
        const subscription = formMethods.watch((currentValues, {name, type}) => {
            // 1. Trigger the global onChange callback with all values (excluding Combined children).
            onChange?.(stripCombinedChildren(currentValues as { [s: string]: any }));

            // 2. Trigger the single value change callback (skip Combined child fields).
            if (onChangeSingleValue && name && type === 'change') {
                if (!combinedChildIds.has(name)) {
                    const value = getValueByPath(currentValues, name);
                    onChangeSingleValue(name, value);
                }
            }
        });
        return () => subscription.unsubscribe();
    }, [formMethods.watch, onChange, onChangeSingleValue, stripCombinedChildren, combinedChildIds]);

    // Return the two concerns separately
    return {
        formMethods, // The original object for FormProvider
        isSubmitting,
        setIsSubmitting,
        handleSubmit: handleSubmitWrapper, // The wrapped function for our UI
    };
};
